import { Link, useNavigate } from "react-router-dom";

const SeasonCard = ({season, handleClick} : any) => {
    const navigate = useNavigate()
    return(        
        
            <div className="col-sm-3">
                <div className="card">
                    <div className="card-body">
                        <h5 className="card-title">Season: {season.startYear + " - " + season.endYear} </h5>
                        <p className="card-text">Age Group: {season.ageGroup}s</p>
                        <Link onClick={() => {navigate('/Fixtures')}}  className="btn btn-primary">View Details</Link>                        
                    </div>
                </div>
            </div>
        
    )
}
export default SeasonCard;
